110	/// Parse a config key's string value to `usize`.
111	///
112	/// - Absent key → `Ok(None)`.
113	/// - Present but unparseable → `Err` naming the key and value
114	///   (malformed config is fatal, not silently ignored).
115	fn parse_usize_key(
116	    map: &HashMap<String, String>,
117	    key: &str,
118	) -> Result<Option<usize>, Box<dyn std::error::Error>> {
119	    match map.get(key) {
120	        None => Ok(None),
121	        Some(s) => s
122	            .parse::<usize>()
123	            .map(Some)
124	            .map_err(|e| format!("config key {key:?}: invalid usize {s:?}: {e}").into()),
125	    }
126	}
