128	/// CLI selector for `--repo <cat>[=<val>]`.
129	///
130	/// - `--repo` absent → `None`.
131	/// - `--repo <cat>` → `Some({ category: cat, value: None })`.
132	/// - `--repo <cat>=<val>` → `Some({ category: cat, value: Some(val) })`.
133	#[derive(Debug, Clone, PartialEq, Eq)]
134	pub struct RepoSelector {
135	    pub category: String,
136	    pub value: Option<String>,
137	}
