139	/// Path to the user config file.
140	///
141	/// - Honors `$XDG_CONFIG_HOME` if set (XDG Base Directory spec).
142	/// - Falls back to `$HOME/.config`.
143	/// - Errors if neither variable is set.
144	pub fn config_path() -> Result<PathBuf, Box<dyn std::error::Error>> {
145	    let base = if let Some(xdg) = std::env::var_os("XDG_CONFIG_HOME") {
146	        PathBuf::from(xdg)
147	    } else if let Some(home) = std::env::var_os("HOME") {
148	        PathBuf::from(home).join(".config")
149	    } else {
150	        return Err("neither $XDG_CONFIG_HOME nor $HOME is set".into());
151	    };
152	    Ok(base.join("vc-x1").join("config.toml"))
153	}
