155	/// Load the user config from the default location.
156	///
157	/// - Missing file → empty `UserConfig`.
158	/// - Malformed file → fatal error.
159	pub fn load() -> Result<UserConfig, Box<dyn std::error::Error>> {
160	    load_from(&config_path()?)
161	}
