163	/// Load the user config from an explicit path.
164	///
165	/// - Missing file → empty `UserConfig`.
166	/// - Malformed file → fatal error (propagated from `toml_simple`).
167	/// - Unknown sections / keys are silently ignored
168	///   (forward-compatible with future schema additions).
169	pub fn load_from(path: &Path) -> Result<UserConfig, Box<dyn std::error::Error>> {
170	    if !path.exists() {
171	        debug!(
172	            "config: file not found at {} — using empty UserConfig",
173	            path.display()
174	        );
175	        return Ok(UserConfig::default());
176	    }
177	    debug!("config: loading from {}", path.display());
178	    let map = toml_simple::toml_load(path)?;
179	
180	    let mut cfg = UserConfig {
181	        default_account: map.get("default.account").cloned(),
182	        default_debug: map.get("default.debug").cloned(),
183	        top_level_repo: None,
184	        accounts: HashMap::new(),
185	        bot_session_items: map.get("bot-session.items").cloned(),
186	        bot_session_result_lines: parse_usize_key(&map, "bot-session.result-lines")?,
187	        bot_session_col_width: parse_usize_key(&map, "bot-session.col-width")?,
188	    };
189	
190	    let mut top_level = AccountConfig::default();
191	    let mut top_level_seen = false;
192	
193	    // Walk all keys; route `repo.*` to top-level, `account.<n>.…`
194	    // to per-account.
195	    for (full_key, value) in &map {
196	        if let Some(suffix) = full_key.strip_prefix("repo.") {
197	            top_level_seen = true;
198	            apply_repo_subkey(&mut top_level, suffix, value);
199	            continue;
200	        }
201	        let Some(rest) = full_key.strip_prefix("account.") else {
202	            continue;
203	        };
204	        let Some((name, suffix)) = rest.split_once('.') else {
205	            continue;
206	        };
207	        let Some(repo_suffix) = suffix.strip_prefix("repo.") else {
208	            continue; // unknown sub-section under [account.<n>]
209	        };
210	        let account = cfg.accounts.entry(name.to_string()).or_default();
211	        apply_repo_subkey(account, repo_suffix, value);
212	    }
213	
214	    if top_level_seen && !cfg.accounts.is_empty() {
215	        return Err(format!(
216	            "{}: mixing top-level [repo] with [account.*] is ambiguous — \
217	             remove top-level [repo] or move it under [account.<name>]",
218	            path.display()
219	        )
220	        .into());
221	    }
222	    if top_level_seen {
223	        cfg.top_level_repo = Some(top_level);
224	    }
225	
226	    debug!(
227	        "config: parsed default_account={:?}, default_debug={:?}, top_level_repo={}, accounts={:?}",
228	        cfg.default_account,
229	        cfg.default_debug,
230	        cfg.top_level_repo.is_some(),
231	        cfg.accounts.keys().collect::<Vec<_>>(),
232	    );
233	    Ok(cfg)
234	}
235	
236	/// Apply one `repo.*` sub-key (e.g. `default`, `category.remote`)
237	/// onto an `AccountConfig`. Used for both the top-level `[repo]`
238	/// path and the `[account.<n>.repo]` path.
239	fn apply_repo_subkey(account: &mut AccountConfig, suffix: &str, value: &str) {
240	    match suffix {
241	        "default" => {
242	            account.repo_default = Some(value.to_string());
243	        }
244	        s if let Some(cat) = s.strip_prefix("category.") => {
245	            account
246	                .repo_category
247	                .insert(cat.to_string(), value.to_string());
248	        }
249	        _ => {} // unknown sub-key; ignore (forward-compat)
250	    }
251	}
