253	/// Resolve `(category, value)` for an init invocation.
254	///
255	/// Three-step chain — each step has its own error message
256	/// pointing at the exact config key to set or CLI arg to pass.
257	///
258	/// - `account_override` — `Some(a)` from `--account a` CLI;
259	///   `None` falls back to `[default].account`.
260	/// - `repo_cli` — the parsed `--repo` selector (or `None` if
261	///   the flag was absent).
262	///
263	/// Fast path: when `repo_cli` provides both `category` and
264	/// `value` (`--repo <cat>=<val>`), the result is fully
265	/// determined by the CLI; no account or category lookup is
266	/// needed and account-related errors are skipped. This makes
267	/// config-less invocations (and test fixtures) work without a
268	/// `~/.config/vc-x1/config.toml`.
269	pub fn resolve_repo(
270	    cfg: &UserConfig,
271	    account_override: Option<&str>,
272	    repo_cli: Option<&RepoSelector>,
273	) -> Result<(String, String), Box<dyn std::error::Error>> {
274	    // Fast path: `--repo <cat>=<val>` is fully self-contained.
275	    if let Some(sel) = repo_cli
276	        && let Some(val) = sel.value.as_ref()
277	    {
278	        debug!(
279	            "resolve_repo: short-circuit — explicit cat={} val={} (from --repo CLI)",
280	            sel.category, val
281	        );
282	        return Ok((sel.category.clone(), val.clone()));
283	    }
284	
285	    // Step 1: pick the AccountConfig to use.
286	    //
287	    // - `--account` CLI → must hit `cfg.accounts[name]`.
288	    // - `[default].account` → must hit `cfg.accounts[that]`.
289	    // - Otherwise fall back to top-level `[repo]` (no account).
290	    // - Otherwise error.
291	    //
292	    // `account_label` is for error messages — section-name "<name>"
293	    // when an account was selected, "<top-level>" for the no-account
294	    // shorthand path.
295	    let (account, account_label, account_source) = match (account_override, &cfg.default_account) {
296	        (Some(name), _) => {
297	            let acct = cfg.accounts.get(name).ok_or_else(|| {
298	                format!("account '{name}' not found in config (no [account.{name}] section)")
299	            })?;
300	            (acct, name.to_string(), "--account CLI")
301	        }
302	        (None, Some(name)) => {
303	            let acct = cfg.accounts.get(name).ok_or_else(|| {
304	                format!(
305	                    "account '{name}' (from [default].account) not found in config \
306	                     (no [account.{name}] section)"
307	                )
308	            })?;
309	            (acct, name.clone(), "[default].account")
310	        }
311	        (None, None) => match cfg.top_level_repo.as_ref() {
312	            Some(r) => (r, String::from("<top-level>"), "top-level [repo]"),
313	            None => {
314	                return Err("no account specified; set [default].account, use \
315	                     --account <name>, or write a top-level [repo] section"
316	                    .into());
317	            }
318	        },
319	    };
320	    debug!(
321	        "resolve_repo: account = {} (from {})",
322	        account_label, account_source
323	    );
324	
325	    // Step 2: category.
326	    let (category, category_source) = match repo_cli {
327	        Some(sel) => (sel.category.clone(), "--repo CLI".to_string()),
328	        None => {
329	            let cat = account.repo_default.clone().ok_or_else(|| {
330	                section_error(
331	                    &account_label,
332	                    "no default category",
333	                    "repo",
334	                    "default",
335	                    "use --repo <cat>",
336	                )
337	            })?;
338	            (cat, format!("[account.{account_label}.repo].default"))
339	        }
340	    };
341	    debug!(
342	        "resolve_repo: category = {} (from {})",
343	        category, category_source
344	    );
345	
346	    // Step 3: value.
347	    let (value, value_source) = match repo_cli.and_then(|s| s.value.clone()) {
348	        Some(v) => (v, "--repo CLI value".to_string()),
349	        None => {
350	            let v = account
351	                .repo_category
352	                .get(&category)
353	                .cloned()
354	                .ok_or_else(|| {
355	                    section_error(
356	                        &account_label,
357	                        &format!("no value for --repo {category}"),
358	                        "repo.category",
359	                        &category,
360	                        &format!("--repo {category}=<val>"),
361	                    )
362	                })?;
363	            (
364	                v,
365	                format!("[account.{account_label}.repo.category].{category}"),
366	            )
367	        }
368	    };
369	    debug!("resolve_repo: value = {} (from {})", value, value_source);
370	
371	    Ok((category, value))
372	}
