374	/// Compose an error message for a missing-key case in `resolve_repo`.
375	///
376	/// Renders as `[account.<label>.<section_subpath>].<leaf>` for
377	/// named accounts and `[<section_subpath>].<leaf>` for the
378	/// top-level `[repo]` shorthand.
379	fn section_error(
380	    account_label: &str,
381	    msg: &str,
382	    section_subpath: &str,
383	    leaf: &str,
384	    cli_alt: &str,
385	) -> String {
386	    let section = if account_label == "<top-level>" {
387	        format!("[{section_subpath}]")
388	    } else {
389	        format!("[account.{account_label}.{section_subpath}]")
390	    };
391	    format!("{msg}; set {section}.{leaf} or use {cli_alt}")
392	}
