395	mod tests {
396	    use super::*;
397	    use std::path::Path;
398	    use std::sync::atomic::{AtomicU64, Ordering};
399	    use std::time::{SystemTime, UNIX_EPOCH};
400	    use std::{fs, path::PathBuf};
401	
402	    use crate::test_tmp_root::{resolve_tmp_root, should_keep_tempdir};
403	
404	    /// Per-process counter so same-nanosecond tempdir collisions
405	    /// yield distinct paths when tests run in parallel.
406	    static COUNTER: AtomicU64 = AtomicU64::new(0);
407	
408	    /// RAII tempdir for `config` tests — sibling of `Fixture` /
409	    /// `FixturePor` / `CliFixture`, scaled to the much smaller
410	    /// "write a config.toml and parse it" use case. Replaces the
411	    /// pre-0.41.1-6.4 `cfg_tempdir(tag) -> PathBuf` helper, which
412	    /// had no `Drop` and leaked one dir per test invocation.
413	    ///
414	    /// Uses the shared `resolve_tmp_root` (`$VC_X1_TEST_TMPDIR` →
415	    /// `std::env::temp_dir()`) and honors `should_keep_tempdir()`
416	    /// (`$VC_X1_TEST_KEEP`) so the same env-var knobs control all
417	    /// fixture types uniformly.
418	    struct CfgTempDir {
419	        dir: PathBuf,
420	    }
421	
422	    impl CfgTempDir {
423	        fn new(tag: &str) -> Self {
424	            let ts = SystemTime::now()
425	                .duration_since(UNIX_EPOCH)
426	                .map(|d| d.as_nanos())
427	                .unwrap_or(0); // OK: clock error → 0 is harmless for unique tempdir naming
428	            let n = COUNTER.fetch_add(1, Ordering::SeqCst);
429	            let dir = resolve_tmp_root().join(format!("vc-x1-cfg-{tag}-{ts}-{n}"));
430	            fs::create_dir_all(&dir).expect("mkdir cfg tempdir");
431	            Self { dir }
432	        }
433	
434	        fn dir(&self) -> &Path {
435	            &self.dir
436	        }
437	    }
438	
439	    impl Drop for CfgTempDir {
440	        fn drop(&mut self) {
441	            if should_keep_tempdir() {
442	                eprintln!("VC_X1_TEST_KEEP set; preserving {}", self.dir.display());
443	            } else {
444	                let _ = fs::remove_dir_all(&self.dir);
445	            }
446	        }
447	    }
448	
449	    /// Write `contents` to `<dir>/config.toml`. Returns the
450	    /// `CfgTempDir` guard alongside the file path so callers can
451	    /// keep the guard alive for the test's scope.
452	    fn write_cfg(tag: &str, contents: &str) -> (CfgTempDir, PathBuf) {
453	        let cfg = CfgTempDir::new(tag);
454	        let path = cfg.dir().join("config.toml");
455	        fs::write(&path, contents).unwrap();
456	        (cfg, path)
457	    }
458	
459	    /// `Drop` removes the tempdir on success: keep the path
460	    /// outside the inner scope, drop the guard, and verify the
461	    /// directory is gone. Pins the leak fix that landed in
462	    /// 0.41.1-6.4.
463	    #[test]
