467	            let cfg = CfgTempDir::new("drop-cleanup");
468	            path = cfg.dir().to_path_buf();
469	            assert!(path.exists(), "tempdir must exist while guard is alive");
470	        }
471	        assert!(
472	            !path.exists(),
473	            "tempdir must be removed after CfgTempDir drops, got: {}",
474	            path.display()
475	        );
476	    }
