202	/// Indent all lines after the first by `n` spaces.
203	///
204	/// Returns the string unchanged if `n == 0` or there is only one line.
205	pub fn indent_body(s: &str, n: usize) -> String {
206	    if n == 0 {
207	        return s.to_string();
208	    }
209	    let pad = " ".repeat(n);
210	    let mut lines = s.lines();
211	    let mut result = match lines.next() {
212	        Some(first) => first.to_string(),
213	        None => return String::new(),
214	    };
215	    for line in lines {
216	        result.push('\n');
217	        if !line.is_empty() {
218	            result.push_str(&pad);
219	        }
220	        result.push_str(line);
221	    }
222	    result
223	}
