254	/// `Parent commit (@-): <chid> <hash> <bookmark> | <title>` style).
255	pub fn format_commit_with_ochid(commit: &Commit, width: usize, bookmarks: &str) -> String {
256	    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
257	    let change_short = &change_hex[..change_hex.len().min(12)];
