280	/// When `bookmarks` is non-empty it is inserted before the title with a `|`
281	/// separator (mirroring jj's `<chid> <hash> <bookmark> | <title>` style).
282	pub fn format_commit_short(commit: &Commit, bookmarks: &str) -> String {
283	    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
284	    let change_short = &change_hex[..change_hex.len().min(12)];
285	    let commit_hex = commit.id().hex();
286	    let commit_short = &commit_hex[..commit_hex.len().min(12)];
287	    let first_line = commit.description().lines().next().unwrap_or(""); // OK: obvious
288	    let title = if first_line.is_empty() {
289	        "(no description set)"
290	    } else {
291	        first_line
292	    };
293	    if bookmarks.is_empty() {
294	        format!("{change_short} {commit_short} {title}")
295	    } else {
296	        format!("{change_short} {commit_short} {bookmarks} | {title}")
297	    }
298	}
299	
300	/// Format: changeID commitID [bookmarks |] first-line, then remaining description lines.
301	///
302	/// Same header rules as `format_commit_short`; body lines follow unchanged.
303	pub fn format_commit_full(commit: &Commit, bookmarks: &str) -> String {
304	    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
305	    let change_short = &change_hex[..change_hex.len().min(12)];
306	    let commit_hex = commit.id().hex();
307	    let commit_short = &commit_hex[..commit_hex.len().min(12)];
308	    let desc = commit.description();
309	    if desc.is_empty() {
310	        return if bookmarks.is_empty() {
311	            format!("{change_short} {commit_short} (no description set)")
312	        } else {
313	            format!("{change_short} {commit_short} {bookmarks} | (no description set)")
314	        };
315	    }
316	    let mut lines = desc.lines();
317	    let first_line = lines.next().unwrap_or(""); // OK: obvious
318	    let mut result = if bookmarks.is_empty() {
319	        format!("{change_short} {commit_short} {first_line}")
320	    } else {
321	        format!("{change_short} {commit_short} {bookmarks} | {first_line}")
322	    };
323	    for line in lines {
324	        result.push('\n');
325	        result.push_str(line);
326	    }
327	    result
328	}
