391	/// Header style between repos in multi-repo output.
392	#[derive(Debug, Clone)]
393	pub enum Header {
394	    /// Show `deco path deco` header per repo.
395	    Label(String),
396	    /// No header at all.
397	    None,
398	}
399	
400	/// Resolve `-l` / `-L` flags into a `Header`.
401	///
402	/// `-L` (no header) takes precedence over `-l` (label decoration).
403	pub fn resolve_header(label: &str, suppress: bool) -> Header {
404	    if suppress {
405	        Header::None
406	    } else {
407	        Header::Label(label.to_string())
408	    }
409	}
410	
411	/// Run a closure once per resolved repo, with optional header decoration between repos.
412	///
413	/// Takes an already-resolved `&[PathBuf]` — the caller is responsible
414	/// for any flag-driven expansion (see `resolve_repos`). Continues past
415	/// errors, printing them to stderr, and returns an error if any
416	/// repo's body failed.
417	pub fn for_each_repo<F>(
418	    repos: &[PathBuf],
419	    header: &Header,
420	    mut body: F,
421	) -> Result<(), Box<dyn std::error::Error>>
422	where
423	    F: FnMut(&Workspace, &Arc<ReadonlyRepo>) -> Result<(), Box<dyn std::error::Error>>,
424	{
425	    let multi = repos.len() > 1;
426	    let mut first = true;
427	    let mut errors: Vec<String> = Vec::new();
428	
429	    for repo_path in repos {
430	        if multi {
431	            match header {
432	                Header::Label(deco) => {
433	                    if !first {
434	                        info!("");
435	                    }
436	                    info!(
437	                        "{}",
438	                        bold(&format!("{deco} {} {deco}", repo_path.display()))
439	                    );
440	                }
441	                Header::None => {}
442	            }
443	        }
444	        first = false;
445	
446	        match load_repo(repo_path) {
447	            Ok((workspace, repo)) => {
448	                if let Err(e) = body(&workspace, &repo) {
449	                    error!("({}): {e}", repo_path.display());
450	                    errors.push(format!("{}: {e}", repo_path.display()));
451	                }
452	            }
453	            Err(e) => {
454	                error!("({}): {e}", repo_path.display());
455	                errors.push(format!("{}: {e}", repo_path.display()));
456	            }
457	        }
458	    }
459	
460	    if errors.is_empty() {
461	        Ok(())
462	    } else {
463	        Err(format!("{} repo(s) had errors", errors.len()).into())
464	    }
465	}
