481	/// Parse and evaluate a revset string, returning commit IDs.
482	pub fn resolve_revset(
483	    workspace: &Workspace,
484	    repo: &Arc<ReadonlyRepo>,
485	    revset_str: &str,
486	) -> Result<Vec<CommitId>, Box<dyn std::error::Error>> {
487	    let aliases_map = RevsetAliasesMap::new();
488	    let fileset_aliases_map = FilesetAliasesMap::new();
489	    let extensions = RevsetExtensions::default();
490	    let workspace_root = workspace.workspace_root().to_path_buf();
491	    let path_converter = RepoPathUiConverter::Fs {
492	        cwd: workspace_root.clone(),
493	        base: workspace_root,
494	    };
495	    let workspace_name = workspace.workspace_name();
496	    let workspace_ctx = RevsetWorkspaceContext {
497	        path_converter: &path_converter,
498	        workspace_name,
499	    };
500	    let context = RevsetParseContext {
501	        aliases_map: &aliases_map,
502	        local_variables: HashMap::new(),
503	        user_email: "",
504	        date_pattern_context: chrono::Utc::now().fixed_offset().into(),
505	        default_ignored_remote: None,
506	        fileset_aliases_map: &fileset_aliases_map,
507	        use_glob_by_default: false,
508	        extensions: &extensions,
509	        workspace: Some(workspace_ctx),
510	    };
511	
512	    let mut diagnostics = RevsetDiagnostics::new();
513	    let expression = jj_lib::revset::parse(&mut diagnostics, revset_str, &context)?;
514	
515	    let no_extensions: &[Box<dyn jj_lib::revset::SymbolResolverExtension>] = &[];
516	    let symbol_resolver = SymbolResolver::new(repo.as_ref(), no_extensions);
517	    let resolved = expression.resolve_user_expression(repo.as_ref(), &symbol_resolver)?;
518	    let revset = resolved.evaluate(repo.as_ref())?;
519	
520	    let mut commit_ids = Vec::new();
521	    for result in revset.commit_change_ids() {
522	        let (commit_id, _change_id) = result?;
523	        commit_ids.push(commit_id);
524	    }
525	    Ok(commit_ids)
526	}
