528	/// Scan `jj bookmark list -a <name>` output for non-tracking remote refs.
529	///
530	/// Tracked remotes appear indented (`  @origin: ...`); non-tracking remotes
531	/// appear at column 0 as `<bookmark>@<remote>: ...`. Returns the
532	/// non-tracking remote name if any is found.
533	pub fn find_non_tracking_remote(list_output: &str, bookmark: &str) -> Option<String> {
534	    let prefix = format!("{bookmark}@");
535	    for line in list_output.lines() {
536	        if line.starts_with(&prefix)
537	            && let Some(rest) = line.strip_prefix(&prefix)
538	            && let Some((remote, _)) = rest.split_once(':')
539	        {
540	            return Some(remote.to_string());
541	        }
542	    }
543	    None
544	}
