570	/// At-rest publish state of a bookmark vs its `@origin` counterpart.
571	#[derive(Debug, PartialEq, Eq)]
572	pub enum PublishState {
573	    /// Local bookmark and `bookmark@origin` point at the same commit.
574	    InSync,
575	    /// `bookmark@origin` does not exist — never pushed.
576	    NeverPushed,
577	    /// Local and origin point at different commits (full commit ids).
578	    Mismatch { local: String, remote: String },
579	}
580	
581	/// Resolve the at-rest publish state of `bookmark` in `repo`.
582	///
583	/// The bookmark only moves inside a push / squash-push run, which
584	/// publishes it in the same invocation — so between commands
585	/// `bookmark == bookmark@origin` is the invariant. A mismatch means
586	/// an earlier publish was lost (or origin moved out from under us).
587	///
588	/// - Read-only: two `jj log` commit-id lookups, nothing else.
589	/// - Errors when the local bookmark itself does not resolve.
590	pub fn bookmark_publish_state(
591	    repo: &Path,
592	    bookmark: &str,
593	) -> Result<PublishState, Box<dyn std::error::Error>> {
594	    let repo_str = repo.to_string_lossy();
595	    let cwd = Path::new(".");
596	    let commit_id = |rev: &str| -> Result<String, Box<dyn std::error::Error>> {
597	        Ok(run(
598	            "jj",
599	            &[
600	                "log",
601	                "-r",
602	                rev,
603	                "--no-graph",
604	                "-T",
605	                "commit_id",
606	                "-R",
607	                &repo_str,
608	            ],
609	            cwd,
610	        )?
611	        .trim()
612	        .to_string())
613	    };
614	    let local = commit_id(bookmark)
615	        .map_err(|e| format!("bookmark '{bookmark}' does not resolve in '{repo_str}': {e}"))?;
616	    // `present(...)` maps a nonexistent remote bookmark to an empty
617	    // result instead of a revset error.
618	    let remote = commit_id(&format!("present({bookmark}@origin)"))?;
619	    Ok(if remote.is_empty() {
620	        PublishState::NeverPushed
621	    } else if local == remote {
622	        PublishState::InSync
623	    } else {
624	        PublishState::Mismatch { local, remote }
625	    })
626	}
627	
628	/// Verify the bot repo's `bookmark` is published at origin.
629	///
630	/// Error-raising wrapper over [`bookmark_publish_state`], used by
631	/// `validate-bot` and push preflight. Fixes nothing (decided
632	/// 2026-07-15: no automatic fixing) — the error names the
633	/// `vc-x1 squash-push` resolution and the caller stops.
634	pub fn verify_bot_published(
635	    bot_repo: &Path,
636	    bookmark: &str,
637	) -> Result<(), Box<dyn std::error::Error>> {
638	    let repo_str = bot_repo.to_string_lossy();
639	    match bookmark_publish_state(bot_repo, bookmark)? {
640	        PublishState::InSync => Ok(()),
641	        PublishState::NeverPushed => Err(format!(
642	            "bot repo '{repo_str}': bookmark '{bookmark}' has never been pushed to origin — \
643	             publish it with `vc-x1 squash-push -R {repo_str}`"
644	        )
645	        .into()),
646	        PublishState::Mismatch { local, remote } => Err(format!(
647	            "bot repo '{repo_str}': '{bookmark}' ({}) does not match '{bookmark}@origin' ({}) — \
648	             an earlier publish was likely lost; publish it with \
649	             `vc-x1 squash-push -R {repo_str}`, then retry",
650	            &local[..local.len().min(12)],
651	            &remote[..remote.len().min(12)]
652	        )
653	        .into()),
654	    }
655	}
