657	/// Walk up from `start` to find the workspace root.
658	///
659	/// The workspace root is the directory whose `.vc-config.toml` has
660	/// `path = "/"`. Returns `None` if no such config is found up to the
661	/// filesystem root — the caller is in a "plain old repo" (POR) with
662	/// no vc-x1 workspace metadata.
663	pub fn find_workspace_root_from(start: &Path) -> Option<PathBuf> {
664	    let mut cur = start.to_path_buf();
665	    loop {
666	        let cfg = cur.join(VC_CONFIG_FILE);
667	        if let Ok(map) = toml_simple::toml_load(&cfg)
668	            && toml_simple::toml_get(&map, "workspace.path").map(String::as_str) == Some("/")
669	        {
670	            return Some(cur);
671	        }
672	        cur = cur.parent()?.to_path_buf();
673	    }
674	}
675	
676	/// Cwd-anchored wrapper over [`find_workspace_root_from`].
677	pub fn find_workspace_root() -> Option<PathBuf> {
678	    let cur = std::env::current_dir().ok()?;
679	    find_workspace_root_from(&cur)
680	}
