682	/// Resolve the workspace's default `--scope`.
683	///
684	/// Reads `<workspace_root>/.vc-config.toml > [workspace] other-repo`:
685	///
686	/// - dual workspace (non-empty `other-repo`) → `Scope([Code, Bot])`
687	/// - single-repo workspace (missing / empty `other-repo`) →
688	///   `Scope([Code])`
689	/// - POR (no `workspace_root`) → `Scope([Code])` — `scope_to_repos`
690	///   resolves `Side::Code` to cwd's `.` when no root is given, so a
691	///   POR run still operates on the current directory.
692	pub fn default_scope(workspace_root: Option<&Path>) -> Scope {
693	    let Some(root) = workspace_root else {
694	        return Scope(vec![Side::Code]);
695	    };
696	    let cfg = match toml_simple::toml_load(&root.join(VC_CONFIG_FILE)) {
697	        Ok(c) => c,
698	        Err(_) => return Scope(vec![Side::Code]),
699	    };
700	    match toml_simple::toml_get(&cfg, "workspace.other-repo") {
701	        Some(v) if !v.is_empty() => Scope(vec![Side::Code, Side::Bot]),
702	        _ => Scope(vec![Side::Code]),
703	    }
704	}
705	
706	/// Resolve a `Scope` to concrete repo paths.
707	///
708	/// - `Side::Code` → `workspace_root` (or cwd's `.` when
709	///   `workspace_root` is None).
710	/// - `Side::Bot` → `workspace_root.join(other-repo)`.
711	///
712	/// Errors when `Side::Bot` is requested but the workspace doesn't
713	/// define one (POR or single-repo workspace).
714	pub fn scope_to_repos(
715	    scope: &Scope,
716	    workspace_root: Option<&Path>,
717	) -> Result<Vec<PathBuf>, Box<dyn std::error::Error>> {
718	    let mut repos = Vec::new();
719	    for side in &scope.0 {
720	        match side {
721	            Side::Code => repos.push(
722	                workspace_root
723	                    .map(Path::to_path_buf)
724	                    .unwrap_or_else(|| PathBuf::from(".")),
725	            ),
726	            Side::Bot => {
727	                let root = workspace_root.ok_or(
728	                    "--scope=bot: not in a vc-x1 workspace (no .vc-config.toml with path = \"/\") — drop --scope or use --scope=code",
729	                )?;
730	                let cfg = toml_simple::toml_load(&root.join(VC_CONFIG_FILE))?;
731	                let other = toml_simple::toml_get(&cfg, "workspace.other-repo")
732	                    .filter(|v| !v.is_empty())
733	                    .ok_or(
734	                        "--scope=bot: no other-repo configured. Add `other-repo = \"…\"` to .vc-config.toml to enable dual-repo operations",
735	                    )?;
736	                repos.push(root.join(other));
737	            }
738	        }
739	    }
740	    Ok(repos)
741	}
742	
743	/// Resolve `CommonArgs.repo` + `CommonArgs.scope` into concrete repo paths.
744	///
745	/// The four `CommonArgs` consumers (`chid` / `desc` / `list` / `show`)
746	/// call this at the start of their body to translate the clap surface
747	/// into the `&[PathBuf]` that `for_each_repo` iterates. Behavior matches
748	/// today's defaults plus a composing rule for the new `--scope` flag:
749	///
750	/// - neither flag → `[.]` (today's no-arg default).
751	/// - `-R PATH` alone → `[PATH]` (today's `-R <path>` behavior;
752	///   workspace context not consulted).
753	/// - `-s ROLES` alone → resolves against `find_workspace_root()` —
754	///   the surrounding workspace if there is one, else POR
755	///   (`Side::Code` → `.`, `Side::Bot` → error).
756	/// - `-R PATH -s ROLES` → resolves with `PATH` as the workspace root
757	///   (overrides `find_workspace_root`). This is the composing case;
758	///   e.g. `chid -R ../foo -s bot` queries `../foo/.claude`.
759	///
760	/// `--scope` is keyword-only (`code|bot|code,bot|bot,code`);
761	/// path-based single-repo operation routes through `-R/--repo`.
762	pub fn resolve_repos(
763	    repo: Option<&Path>,
764	    scope: Option<&Scope>,
765	) -> Result<Vec<PathBuf>, Box<dyn std::error::Error>> {
766	    match (repo, scope) {
767	        (None, None) => Ok(vec![PathBuf::from(".")]),
768	        (Some(p), None) => Ok(vec![p.to_path_buf()]),
769	        (Some(p), Some(s)) => scope_to_repos(s, Some(p)),
770	        (None, Some(s)) => scope_to_repos(s, find_workspace_root().as_deref()),
771	    }
772	}
773	
774	/// Resolved shared params for the read-only commit-query subcommands
775	/// (`chid` / `desc` / `list` / `show`). Built once at the binary edge
776	/// from `CommonArgs` via `TryFrom`; each subcommand's `XxxParams`
777	/// embeds this.
778	///
779	/// - `spec` — resolved `DotSpec` (parsed `..` notation + per-side
780	///   count budget).
781	/// - `header` — resolved inter-repo `Header` (label vs none).
782	/// - `repos` — resolved repo paths (`-R` + `-s` → `Vec<PathBuf>`).
783	#[derive(Debug)]
784	pub struct CommonParams {
785	    pub spec: DotSpec,
786	    pub header: Header,
787	    pub repos: Vec<PathBuf>,
788	}
789	
790	impl TryFrom<&CommonArgs> for CommonParams {
791	    type Error = String;
792	
793	    /// Resolve clap `CommonArgs` into clap-free `CommonParams`: run
794	    /// `resolve_spec` / `resolve_header` / `resolve_repos` at the
795	    /// binary edge. Fallible because `resolve_repos` can fail
796	    /// (workspace lookup, path issues).
797	    fn try_from(a: &CommonArgs) -> Result<Self, String> {
798	        let spec = resolve_spec(a.pos_rev.as_deref(), a.pos_count, &a.revision, a.limit, "@");
799	        let header = resolve_header(&a.label, a.no_label);
800	        let repos = a.resolve_repos().map_err(|e| e.to_string())?;
801	        Ok(CommonParams {
802	            spec,
803	            header,
804	            repos,
805	        })
806	    }
807	}
