1	//! Shared harness for CLI subprocess integration tests.
2	//!
3	//! Lives under `tests/common/` so Cargo treats it as a shared module
4	//! (a top-level `tests/common.rs` would be compiled as its own test
5	//! crate). Each `tests/<name>.rs` declares `mod common;` to opt in.
6	//!
7	//! Cargo compiles each `tests/*.rs` as its own crate; helpers used
8	//! by some test crates but not others get dead-code warnings in the
9	//! crates that don't reach them. The crate-level allow below mutes
10	//! that — it's the standard idiom for shared `tests/common/`.
11	//!
12	//! - `vc_x1()` returns a `Command` for the binary Cargo built for
13	//!   the current test crate, resolved via the
14	//!   `CARGO_BIN_EXE_<bin-name>` env var with the name derived
15	//!   from `CARGO_PKG_NAME` — rename-proof, see Cargo.toml.
16	//! - `run_ok` / `run_err` wrap `Command::output` with a panic on
17	//!   the unexpected exit status, embedding stdout/stderr in the
18	//!   message so failures are debuggable.
19	//! - `CliFixture` owns a per-test tempdir under `$TMPDIR` and
20	//!   removes it on drop. Subprocesses get `HOME` overridden to a
21	//!   tempdir-scoped path so user config can't leak into or out of
22	//!   the test.
23	
24	#![allow(dead_code)]
25	
26	use std::path::{Path, PathBuf};
27	use std::process::{Command, Output};
28	use std::sync::atomic::{AtomicU64, Ordering};
29	use std::time::{SystemTime, UNIX_EPOCH};
30	
31	// Single source of truth for tempdir-root resolution, shared with
32	// the binary's unit-test harness via `#[path]` include. See
33	// `src/test_tmp_root.rs` for the rationale and dependency-free
34	// constraint.
35	#[path = "../../src/test_tmp_root.rs"]
36	mod test_tmp_root;
37	use test_tmp_root::{resolve_tmp_root, should_keep_tempdir};
38	
39	static COUNTER: AtomicU64 = AtomicU64::new(0);
40	
41	/// Build a unique tempdir path for a CLI test.
42	///
43	/// Mirrors `src/test_helpers::unique_base`'s shape (timestamp +
44	/// per-process counter) but uses a `vc-x1-cli-test-` prefix to
45	/// distinguish from the in-process fixtures' `vc-x1-test-` paths.
46	pub fn unique_base(tag: &str) -> PathBuf {
47	    let ts = SystemTime::now()
48	        .duration_since(UNIX_EPOCH)
49	        .map(|d| d.as_nanos())
50	        .unwrap_or(0);
51	    let n = COUNTER.fetch_add(1, Ordering::SeqCst);
52	    resolve_tmp_root().join(format!("vc-x1-cli-test-{tag}-{ts}-{n}"))
53	}
54	
55	/// Build a `Command` invoking the binary that Cargo built for
56	/// this test crate. Cargo sets `CARGO_BIN_EXE_<bin-name>` to the
57	/// full path of the freshly-built binary; the var name is built
58	/// from `CARGO_PKG_NAME` (the default bin name is the package
59	/// name) so a Cargo.toml rename needs no edit here.
60	pub fn vc_x1() -> Command {
61	    Command::new(env!(concat!("CARGO_BIN_EXE_", env!("CARGO_PKG_NAME"))))
62	}
63	
64	/// Run `cmd`, panicking with stdout/stderr if it does not exit 0.
65	pub fn run_ok(cmd: &mut Command) -> Output {
66	    let out = cmd.output().expect("spawn vc-x1");
67	    if !out.status.success() {
68	        panic!(
69	            "vc-x1 unexpectedly failed: status={:?}\n--- stdout ---\n{}\n--- stderr ---\n{}",
70	            out.status,
71	            String::from_utf8_lossy(&out.stdout),
72	            String::from_utf8_lossy(&out.stderr),
73	        );
74	    }
75	    out
76	}
77	
78	/// Run `cmd`, panicking with stdout/stderr if it exits 0.
79	pub fn run_err(cmd: &mut Command) -> Output {
80	    let out = cmd.output().expect("spawn vc-x1");
81	    if out.status.success() {
82	        panic!(
83	            "vc-x1 unexpectedly succeeded\n--- stdout ---\n{}\n--- stderr ---\n{}",
84	            String::from_utf8_lossy(&out.stdout),
85	            String::from_utf8_lossy(&out.stderr),
86	        );
87	    }
88	    out
89	}
90	
91	/// RAII tempdir owner for CLI tests.
92	///
93	/// - `base` is a freshly-allocated unique tempdir; it does *not*
94	///   exist on disk until the caller (or the subprocess) creates it.
95	/// - `home` is a sibling under `base` reserved for `HOME` override
96	///   on subprocesses, so config reads don't escape the fixture.
97	/// - `Drop` removes the whole `base` tree (best-effort).
98	pub struct CliFixture {
99	    pub base: PathBuf,
100	    pub home: PathBuf,
101	}
102	
103	impl CliFixture {
104	    /// Allocate a fresh fixture; create `home/` so `HOME=…` points
105	    /// at a real directory.
106	    pub fn new(tag: &str) -> Self {
107	        let base = unique_base(tag);
108	        let home = base.join("home");
109	        std::fs::create_dir_all(&home).expect("mkdir cli fixture home");
110	        CliFixture { base, home }
111	    }
112	
113	    /// Build a `vc-x1` `Command` with `HOME` pointed at the
114	    /// fixture's isolated home dir, so user config can't leak.
115	    pub fn cmd(&self) -> Command {
116	        let mut c = vc_x1();
117	        c.env("HOME", &self.home);
118	        c
119	    }
120	
121	    /// Convenience: join a relative path under `base`.
122	    pub fn path(&self, rel: impl AsRef<Path>) -> PathBuf {
123	        self.base.join(rel)
124	    }
125	}
126	
127	impl Drop for CliFixture {
128	    /// Remove the fixture tree on drop. Suppressed when
129	    /// `$VC_X1_TEST_KEEP` is set — see
130	    /// `test_tmp_root::should_keep_tempdir`.
131	    fn drop(&mut self) {
132	        if should_keep_tempdir() {
133	            eprintln!("VC_X1_TEST_KEEP set; preserving {}", self.base.display());
134	        } else {
135	            let _ = std::fs::remove_dir_all(&self.base);
136	        }
137	    }
138	}
