    .expect("write vc-config");
    let out = run_err(
        fx.cmd()
            .current_dir(&fx.base)
            .arg("config")
            .args(["--validate", "--home", "workspace"]),
    );
    let stderr = String::from_utf8_lossy(&out.stderr);
    assert!(
